While(
[
names = "";
// query list of container IDs
list =
MBS
( "
CNContactStore.Containers
" );
count = ValueCount(list);
index = 1
] ;
index ≤ count ;
[
id = GetValue(list; index);
// query name for each ID
name =
MBS
( "CNContainer.Name"; id);
names = names & id & " -> " &name & ¶;
index = index + 1
] ;
// return all the names
names )
